import{_ as a,j as n,o as i,v as e}from"./chunks/framework.dn0DPyqd.js";const s=JSON.parse('{"title":"Kafka Brokers là gì ?","description":"","frontmatter":{"footer":true,"title":"Kafka Brokers là gì ?","authors":["lethanh"],"date":"2024-06-10T00:00:00.000Z","outline":"deep","draft":true,"group":"2.1 Kafka"},"headers":[{"level":2,"title":"Kafka Brokers là gì ?","slug":"kafka-brokers-la-gi","link":"#kafka-brokers-la-gi","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers","slug":"vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","link":"#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers","slug":"vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","link":"#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","children":[]},{"level":2,"title":"Topics và partitions","slug":"topics-va-partitions","link":"#topics-va-partitions","children":[{"level":3,"title":"Topics","slug":"topics","link":"#topics","children":[]},{"level":3,"title":"partitions","slug":"partitions","link":"#partitions","children":[{"level":4,"title":"Cách Kafka Broker map record đến partition.","slug":"cach-kafka-broker-map-record-đen-partition","link":"#cach-kafka-broker-map-record-đen-partition","children":[]}]},{"level":3,"title":"Offsets","slug":"offsets","link":"#offsets","children":[]},{"level":3,"title":"Xác định số lượng partition sử dụng","slug":"xac-đinh-so-luong-partition-su-dung","link":"#xac-đinh-so-luong-partition-su-dung","children":[]},{"level":3,"title":"Tạo một topic","slug":"tao-mot-topic","link":"#tao-mot-topic","children":[]},{"level":3,"title":"Segments","slug":"segments","link":"#segments","children":[]}]},{"level":2,"title":"Một số lưu ý về Kafka Brokers","slug":"mot-so-luu-y-ve-kafka-brokers","link":"#mot-so-luu-y-ve-kafka-brokers","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","filePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","lastUpdated":1730733249000}'),t={name:"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md"},r=[e('<nav class="table-of-contents"><ul><li><a href="#kafka-brokers-la-gi">Kafka Brokers là gì ?</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers</a></li><li><a href="#topics-va-partitions">Topics và partitions</a><ul><li><a href="#topics">Topics</a></li><li><a href="#partitions">partitions</a><ul><li><a href="#cach-kafka-broker-map-record-đen-partition">Cách Kafka Broker map record đến partition.</a></li></ul></li><li><a href="#offsets">Offsets</a></li><li><a href="#xac-đinh-so-luong-partition-su-dung">Xác định số lượng partition sử dụng</a></li><li><a href="#tao-mot-topic">Tạo một topic</a></li><li><a href="#segments">Segments</a></li></ul></li><li><a href="#mot-so-luu-y-ve-kafka-brokers">Một số lưu ý về Kafka Brokers</a></li></ul></nav><h1 id="overview-bai-viet-ve-kafka-brokers-la-gi" tabindex="-1">Overview bài viết về Kafka Brokers là gì ? <a class="header-anchor" href="#overview-bai-viet-ve-kafka-brokers-la-gi" aria-label="Permalink to &quot;Overview bài viết về Kafka Brokers là gì ?&quot;">​</a></h1><ul><li>Bài này sẽ giải thích cách kafka Broker hoạt động và lưu trữ trong Kafka event streaming platform</li><li>Mô tả cách Kafka Brokers xử lý các yêu cầu từ client cho việc ghi và đọc records.</li><li>Hiểu về Topic và Partitions</li><li>Sử dụng JMX metrics để kiểm tra Brokers</li></ul><h2 id="kafka-brokers-la-gi" tabindex="-1">Kafka Brokers là gì ? <a class="header-anchor" href="#kafka-brokers-la-gi" aria-label="Permalink to &quot;Kafka Brokers là gì ?&quot;">​</a></h2><ul><li>Kafka Brokers hay có thể gọi là Kafka server trong Kafka architecture và nó sẽ đóng vai trò lưu trữ dữ liệu(Storage layer) và nó có thể chạy thành một cluster và nó có thể mở rộng ra nhiều data centers. <img src="/assets/kafka-architecture-view.B_rra7lS.png" alt="kafka-architecture-view.png"></li><li>Kafka Brokers chịu trách nghiệm quản lý dữ liệu( Bao gồm lưu trữ, đọc và replication(Tạo bản sao để sao lưu) ), quản lý topic và partition và quản lý offset.</li><li>Tất nhiên, Kafka Brokers cũng nhận và xử lý trực tiếp các request từ client. <img src="/assets/kafka-handler-request.tA_aT67K.jpg" alt="kafka-handler-request.jpg"></li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" tabindex="-1">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers&quot;">​</a></h2><ul><li>Khi Produce muốn gửi Record đến Broker, Client Produce gửi records đến Broker đeer lưu trữ và consumer client có thể đọc các record đó sau. <img src="/assets/kafka-produce.MttxNzo5.jpg" alt="kafka-produce.jpg"> Hình ảnh phía trên mô tả Produce gửi record đến Brokers, trong thực tế, nhiều Client Produce sẽ giao tiếp với 1 số các Brokers trong cụm.</li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" tabindex="-1">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers&quot;">​</a></h2><p>Sau khi nói về yêu cầu của Produce chúng ta sẽ nói đến Consumer.</p><ul><li>Consumer client đưa ra yêu cầu đến Broker để đọc(Sử dụng) các Record từ một topic được các Produce gửi trước đó đên Broker. <img src="/assets/kafka-Consumer.PLcOqiQl.jpg" alt="kafka-Consumer.jpg"></li><li>Một điều quan trọng là sử dụng Record sẽ không làm ảnh hưởng đến việc lưu dữ liệu(Không bị mất sau khi đọc) hoặc việc sử dụng Record bởi các Consumer khác(Các consumer khác vẫn có thể đọc)</li></ul><h2 id="topics-va-partitions" tabindex="-1">Topics và partitions <a class="header-anchor" href="#topics-va-partitions" aria-label="Permalink to &quot;Topics và partitions&quot;">​</a></h2><h3 id="topics" tabindex="-1">Topics <a class="header-anchor" href="#topics" aria-label="Permalink to &quot;Topics&quot;">​</a></h3><ul><li>Kafka brokers sử dụng File system để lưu trữ bằng cách nối thêm các Record đến cuối cùng file trong một topic.</li><li>Một topic đại diện cho tên của Folder chưa tệp Kafka nối thêm các Record <img src="/assets/kafka-topic-1.AVPSldcv.jpg" alt="kafka-topic-1.jpg"></li><li>Kafka Brokers sẽ nhận key-value message dưới dạng raw byte, lưu trữ và phục vụ các yêu cầu đọc với cùng định dạng(Raw data). <ul><li>Kafka Brokers không biết về data type của Record(Chỉ nhận được các byte), bằng cách làm việc với raw byte, Brokers không mất thời gian deserializing hoặc serializing dữ liệu nên mạng lại hiệu suất cao hơn.</li></ul></li></ul><h3 id="partitions" tabindex="-1">partitions <a class="header-anchor" href="#partitions" aria-label="Permalink to &quot;partitions&quot;">​</a></h3><ul><li>Các topic sẽ đươc partition, một Partition là một số nguyên(number) bắt đầu từ 0. Vì vậy nếu một topic có 3 partition thì sẽ có số partition là 0, 1, 2.</li><li>Kafka brokers gắn số partition và đuôi của folder topic với format <code>{Topic name}-{partition number}</code>. <ul><li>Ví dụ một Topic tên <code>my-topic-2</code> có <code>5</code> partition thì tên sẽ như sau : <code>my-topic-2-0</code>, <code>my-topic-2-1</code>, <code>my-topic-2-2</code>, <code>my-topic-2-3</code>, , <code>my-topic-2-4</code>, <img src="/assets/kafka-partition-number.H1MC9uuH.jpg" alt="kafka-partition-number.jpg"></li></ul></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>│   ....</span></span>\n<span class="line"><span>│   recovery-point-offset-checkpoint</span></span>\n<span class="line"><span>│   replication-offset-checkpoint</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-0</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-1</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-2</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-3</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-4</span></span>\n<span class="line"><span>│      00000000000000000000.index</span></span>\n<span class="line"><span>│      00000000000000000000.log</span></span>\n<span class="line"><span>│      00000000000000000000.timeindex</span></span>\n<span class="line"><span>│      leader-epoch-checkpoint</span></span>\n<span class="line"><span>│      partition.metadata</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br></div></div><ul><li>Nhìn vào folder chúng ta có thể dễ hiểu được với tên topic là một nhóm dữ liệu và partititon là các đơn vị lưu trữ.</li><li>Trong hầu hết các case, số lượng của Partition càng cao thì throughput(Thông lượng) sẽ càng cao.</li></ul><h4 id="cach-kafka-broker-map-record-đen-partition" tabindex="-1">Cách Kafka Broker map record đến partition. <a class="header-anchor" href="#cach-kafka-broker-map-record-đen-partition" aria-label="Permalink to &quot;Cách Kafka Broker map record đến partition.&quot;">​</a></h4><p>Thực tế việc xác định partition sẽ được lầm ở bên Client.</p><ul><li>Đã có 1 blog viết chi tiết ở đây : <a href="./../../blog/2024-08-07-Kafka-producer-da-khong-con-Round-Robin-Partition-voi-key-null.html">Click vào đây để xem</a></li></ul><h3 id="offsets" tabindex="-1">Offsets <a class="header-anchor" href="#offsets" aria-label="Permalink to &quot;Offsets&quot;">​</a></h3><ul><li>Khi broker thêm một Record nó sẽ thêm một <code>id</code> được gọi là <code>offset</code>. Một <code>offset</code> sẽ bắt đầu từ <code>0</code> và là number, nó sẽ tặng lên 1 mỗi khi thêm một Record. <img src="/assets/kafka-offset.sMIJqZq4.png" alt="kafka-offset.png"></li><li>Vì các Record mới luôn được thêm ở cuối của file, nên nó được sắp xếp theo offset.</li><li>Kafka đảm bảo Record order được sẵp xếp theo thứ tự trên cùng một partition chứ không phải trên các partition khác.</li></ul><details class="details custom-block"><summary>Ví dụ</summary><p>Có một topic với partition và có 10 Record.</p><ul><li>Partition 1: R1 (Offset 0) , R3(Offset 2) , R6(Offset 5), R7(Offset 6)</li><li>Partition 2:, R2(Offset 1), R4(Offset 3), R5(Offset 4), R8(Offset 7), R9(Offset 8), R10(Offset 9)</li></ul><p>Partition 1 và 2 sẽ có thứ tự offset tăng dần.</p></details><p>Consumer sử dụng <code>offset</code> để xác định vị trí của Record họ đã sử dụng, bằng cách này Consumer sẽ tìm các Record có <code>offset</code> cao hơn đã được Consumer đọc. <img src="/assets/kafka-offset-2.kQgsXxuz.png" alt="kafka-offset-2.png"></p><h3 id="xac-đinh-so-luong-partition-su-dung" tabindex="-1">Xác định số lượng partition sử dụng <a class="header-anchor" href="#xac-đinh-so-luong-partition-su-dung" aria-label="Permalink to &quot;Xác định số lượng partition sử dụng&quot;">​</a></h3><ul><li>Việc chọn số lượng partition khi tạo một topic là một điều khó khắn, nó là cả một nghệ thuật.</li><li>Một trong nhưng cân nhắc quan trọng là đầu tiên là <strong>lượng dữ liệu chạy chảy vào topic đó</strong>. Nhiều data thì chúng ta có thể có nhiều partition hơn để throughput(Thông lượng) cao hơn, tuy nhiên nhiều partition chúng ta cũng sẽ có những đánh đổi nhất định. <ul><li>Tăng số lượng partition sẽ tăng số lượng TCP connect và open file. Và thời gian để Consumer xử lý một Record cũng là một điều ảnh hưởng đến throughput. Nếu thời gian xử lý cần rất nhiều thì việc thêm partition có thể hữu ích nhưng việc xử lý chậm vẫn làm hiệu xuất không được tốt.</li></ul></li><li>Bắt đầu tốt nhất chúng ta nên sử dụng càng ít partition càng tốt. Bởi vì chúng ta có thể tăng số lượng partition nhưng không thể giảm partition.</li><li>Nếu khi tạo topic chúng ta có thể xác định số lượng Consumer thì chúng ta nên cài đặt partition bằng với số lượng của consumer. Điều này là best cho phiên bản kafk &lt; 2.4 bởi vì các phiên bản cũ sẽ <code>Round-robin</code> các partition nhưng ở phiên bản &gt;= 2.4 thì đã random partiton cho mỗi batch của topic.</li><li>Nếu topic này có thẻ Chúng ta sẽ có 1 chủ đề chi tiết hơn về điều này.</li></ul><h3 id="tao-mot-topic" tabindex="-1">Tạo một topic <a class="header-anchor" href="#tao-mot-topic" aria-label="Permalink to &quot;Tạo một topic&quot;">​</a></h3><ul><li>Để tạo một topic mới chúng ta có thể sử dụng cmd <code>kafka-topics</code> với param <code>--create</code>.</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>kafka-topics --create --if-not-exists --topic first-topic\\ #1</span></span>\n<span class="line"><span>--bootstrap-server localhost:9092\\ #2 </span></span>\n<span class="line"><span>--replication-factor 1\\ #3  </span></span>\n<span class="line"><span>--partitions 1 #4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><code>#1</code><ul><li>Với <code>kafka-topics</code> là câu lệnh để khởi chạy một <code>cmd</code></li><li><code>--create</code> là param để mong muốn tạo mới một topic với và <code>--if-not-exists</code> là param tạo nếu topic chưa tồn tại, còn đã tồn tại sẽ bỏ qua. (Nếu không có cờ này, nếu đã tồn tại sẽ trả về lỗi ngoại lệ <code>Error while executing topic command : Topic &#39;first-topic&#39; already exists.</code> )</li><li><code>--topic</code> là param để xác định tên topic</li><li><code>first-topic</code> là tên topic</li></ul></li><li><code>#2</code> với <code>--bootstrap-serve</code> là danh sách server kafka để <code>cmd</code> thực hiện kết nối để gửi request tạo topic</li><li><code>#3</code> với <code>--replication-factor</code> là số lượng replication để mỗi partition sễ được nhận rộng lên bao nhiêu. <ul><li>Là trị là số và phải ở giữa <code>1 và 32767</code></li><li>Số lượng phải nhỏ hơn hoặc bằng với số lượng Broker</li><li>Nếu không có parma này, default sẽ được lấy ở config trong Broker <code>default.replication.factor</code></li></ul></li><li><code>#4</code> với <code>--partitions 1</code> là số lượng partition cho topic này. Với số lượng cần lớn hơn <code>0</code><ul><li>Nếu không có parm này thì default sẽ được lấy trong <code>num.partitions</code></li></ul></li></ul><h3 id="segments" tabindex="-1">Segments <a class="header-anchor" href="#segments" aria-label="Permalink to &quot;Segments&quot;">​</a></h3><ul><li>Như chúng ta đã biết Broker sẽ thêm các Record vào các partition. Tuy nhiên Broker sẽ không thêm vào một tập partition duy nhất, nếu làm vậy tệp partition này sẽ khổng lồ.</li><li>Broker sẽ chia thành các tệp nhỏ thành các phần riêng biệt và được gọi là segments. <img src="/assets/kafka-partition-log-segments.48Zu1TVk.png" alt="kafka-partition-log-segments.png"><img src="/assets/kafka-partition-log-segments-file.24ReTyft.png" alt="kafka-partition-log-segments-file.png"></li><li>Việc sử dụng Segments sẽ giúp thực hiện push Record mới và thực hiện truy suất bản ghi bằng offset trở lên dễ dàng hơn.</li><li>Mặc định kafka Broker sẽ để mỗi segment là một <a href="https://docs.confluent.io/platform/current/installation/configuration/topic-configs.html#segment-bytes" target="_blank" rel="noreferrer">1G</a> hoặc chúng ta có thể chỉ định ở <code>segment.bytes</code>. Khi đến ngưỡng segment sẽ được close và một segment mới được tạo. <ul><li>Kích thước segment nhỏ hơn có nghĩa là các tệp phải được đóng và phân bổ thường xuyên hơn, điều này làm giảm hiệu quả chung của việc ghi đĩa.</li></ul></li><li>Khi một segment bị close nó có thể được coi là expire(Hết hạn, bởi vì dữ liệu đã tồn tại quá lâu), việc điều chỉnh kích thước của các segment cũng rất quan trọng.</li><li>Chúng ta cũng có 1 config nữa đó là <code>segment.ms</code>, đây là thời gian nếu <code>segment</code> chưa đến ngưỡng giới hạn dung lượng thì kafka cũng sẽ close segment và tạo ra một segment mới. Default là 1 tuần.</li><li>Lưu ý : <code>segment.ms</code> và <code>segment.bytes</code> là config của từng topic</li><li><a href="https://kafka.apache.org/30/generated/topic_config.html" target="_blank" rel="noreferrer">Danh sách biến topic config</a></li></ul><h2 id="mot-so-luu-y-ve-kafka-brokers" tabindex="-1">Một số lưu ý về Kafka Brokers <a class="header-anchor" href="#mot-so-luu-y-ve-kafka-brokers" aria-label="Permalink to &quot;Một số lưu ý về Kafka Brokers&quot;">​</a></h2><ul><li>Nếu tạo một Cluster kafka thì độ trễ của network nên ở mức dưới 15ms, vì việc liên lạc giữa các Kafka brokers là rất nhiều (Cả zookeeper nếu sử dụng zookeeper )</li></ul><h1 id="ref" tabindex="-1">REF: <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF:&quot;">​</a></h1><ul><li><a href="https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/" target="_blank" rel="noreferrer">https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/</a></li><li><strong>Kafka book</strong>: <a href="/study/thanhlv-study-2024/static/Kafka%20Event%20Streaming%20Platform%20In%20Action.pdf">Kafka Event Streaming Platform In Action.pdf</a></li></ul>',36)];const c=a(t,[["render",function(a,e,s,t,c,o){return i(),n("div",null,r)}]]);export{s as __pageData,c as default};
